vector<long long> Solution::maximumEvenSplit(long long finalSum) {
    if (finalSum % 2 == 1) return {};
    long long start = 4, count = 2;
    vector<long long> res;
    while (finalSum > 0) {
        long long num = min(finalSum, start);
        finalSum -= num;
        res.push_back(num);
        start += 2;
        count++;
    }
    return res;
}
```

